                   }
                   emitter.onSuccess(opt.get());
               } else {
                   emitter.onComplete();
               }
            });
        });

        return maybe.isEmpty().flatMapPublisher(empty -> {
            if (empty) {
               return Publishers.convertPublisher(
                       context.proceed(), Flowable.class)
                       .flatMap(o -> {
